questionvariables.text:
/* 1. Motion Parameters */
a_up: 1 + rand(3);     /* Acceleration: 1 to 2 m/s^2 */
v_max: 3 + rand(3);          /* Constant velocity: 3 to 5 m/s */
t_const: 4 + rand(5);        /* Time at constant velocity: 4 to 8 s */

/* 2. Time Calculations */
t_accel: v_max / a_up;       /* Time to reach max speed (v = u + at) */
t_decel: t_accel;            /* Assume symmetrical deceleration */
t_total: (2 * t_accel) + t_const;

/* 3. Displacement Calculations (Area under V-T Graph) */
dist_accel: 1/2 * v_max * t_accel;
dist_const: v_max * t_const;
total_disp: (2 * dist_accel) + dist_const;

/* 4. Teacher Answers */
ta1: t_accel;
ta2: total_disp;
